'use client';

import { motion } from 'framer-motion';

const Location = () => {
  return (
    <section id="locations" className="py-24 bg-beige-light">
      <div className="container mx-auto px-6 max-w-7xl">
        <div className="bg-white rounded-[3rem] shadow-strong overflow-hidden flex flex-col lg:flex-row border border-beige-main">
          
          {/* Текстовый блок */}
          <div className="lg:w-1/2 p-10 lg:p-20 flex flex-col justify-center">
            <h2 className="text-green-dark mb-6 tracking-tight">Ждем вас в гости</h2>
            <div className="space-y-8">
              <div className="flex gap-5">
                <div className="text-3xl">📍</div>
                <div>
                  <h4 className="font-bold text-green-dark mb-1">Наш адрес</h4>
                  <p className="text-text-medium">г. Минск, пр-т Победителей, 110<br/>(напротив Арена-Сити)</p>
                </div>
              </div>
              <div className="flex gap-5">
                <div className="text-3xl">🚗</div>
                <div>
                  <h4 className="font-bold text-green-dark mb-1">Парковка</h4>
                  <p className="text-text-medium">Бесплатная парковка для посетителей<br/>прямо перед входом.</p>
                </div>
              </div>
            </div>
            
            <motion.button 
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              className="mt-12 btn-primary w-fit px-10 rounded-2xl"
            >
              Открыть в Яндекс Картах
            </motion.button>
          </div>

          {/* Заглушка под карту (Карта всегда добавляет веса) */}
          <div className="lg:w-1/2 bg-beige-main min-h-[400px] relative grayscale hover:grayscale-0 transition-all duration-700">
            <iframe 
               src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d2348.653654407!2d27.4727!3d53.93!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2zNTPCsDU1JzQ4LjAiTiAyN8KwMjgnMjEuNyJF!5e0!3m2!1sru!2sby!4v1630000000000!5m2!1sru!2sby"
               className="absolute inset-0 w-full h-full border-0"
               allowFullScreen
               loading="lazy"
            ></iframe>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Location;